// ---------- 1. Get data from previous node ----------
const data = $('TR accounts api: process last audio in chat').first().json

// ---------- 2. Safely extract utterances ----------
const utterances = data.transcription?.results?.utterances || [];

if (!utterances.length) {
  return [{
    json: {
      dialogue: [],
      markdown_output: "_No utterances found in transcription_",
    }
  }];
}

// ---------- 3. Sort utterances by start time ----------
utterances.sort((a, b) => a.start - b.start);

// ---------- 4. Merge consecutive utterances of the same speaker with punctuation ----------
const dialogue = [];
let currentSpeaker = null;
let currentText = '';
let startTime = null;
let endTime = null;
let confidences = [];

for (const u of utterances) {
  const speaker = u.speaker ?? 0;
  const text = u.transcript.trim();

  if (currentSpeaker === null) {
    // Initialize first block
    currentSpeaker = speaker;
    currentText = text;
    startTime = u.start;
    endTime = u.end;
    confidences = [u.confidence ?? 0];
  } else if (speaker === currentSpeaker) {
    // Same speaker → append with proper punctuation
    const lastChar = currentText.slice(-1);
    const punctuation = ['.', '!', '?'].includes(lastChar) ? ' ' : '. ';
    currentText += punctuation + text;
    endTime = u.end;
    confidences.push(u.confidence ?? 0);
  } else {
    // Speaker changed → push previous block
    dialogue.push({
      speaker: currentSpeaker,
      text: currentText,
      start: Number(startTime.toFixed(2)),
      end: Number(endTime.toFixed(2)),
      confidence_avg: (confidences.reduce((a,b)=>a+b,0)/confidences.length).toFixed(3),
    });

    // Start new speaker block
    currentSpeaker = speaker;
    currentText = text;
    startTime = u.start;
    endTime = u.end;
    confidences = [u.confidence ?? 0];
  }
}

// ---------- 5. Push the last speaker block ----------
if (currentText) {
  dialogue.push({
    speaker: currentSpeaker,
    text: currentText,
    start: Number(startTime.toFixed(2)),
    end: Number(endTime.toFixed(2)),
    confidence_avg: (confidences.reduce((a,b)=>a+b,0)/confidences.length).toFixed(3),
  });
}

// ---------- 6. Create Markdown output ----------
const markdown = dialogue
  .map(d => `**Speaker ${d.speaker} (${d.start}s–${d.end}s):**\n${d.text}`)
  .join("\n\n");

// ---------- 7. Return structured data ----------
return [{
  json: {
    dialogue,
    markdown_output: markdown,
    meta: {
      duration: data.transcription?.metadata?.duration || null,
      model: data.transcription?.metadata?.model_info
        ? Object.values(data.transcription.metadata.model_info)[0]?.name
        : null,
    }
  }
}];
